#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int x1, y1, x2, y2, x3, y3, x4, y4;
        scanf("%d %d %d %d %d %d %d %d", &x1, &y1, &x2, &y2, &x3, &y3, &x4, &y4);
        double area = 0.5 * ((x1 * y2 + x2 * y3 + x3 * y4 + x4 * y1) - (x2 * y1 + x3 * y2 + x4 * y3 + x1 * y4));
        if (area < 0) area = -area;
        double perimeter = sqrt(pow(x2 - x1, 2) + pow(y2 - y1, 2)) + sqrt(pow(x3 - x2, 2) + pow(y3 - y2, 2)) + sqrt(pow(x4 - x3, 2) + pow(y4 - y3, 2)) + sqrt(pow(x1 - x4, 2) + pow(y1 - y4, 2));
        printf("Case %d: %d\n", t + 1, (int)area + (int)perimeter + 1);
    }
    return 0;
}

