            if (area < 0) area = -area;
            double perimeter = Math.sqrt(Math.pow(x2 - x1, 2) + Math.pow(y2 - y1, 2)) + Math.sqrt(Math.pow(x3 - x2, 2) + Math.pow(y3 - y2, 2)) + Math.sqrt(Math.pow(x4 - x3, 2) + Math.pow(y4 - y3, 2)) + Math.sqrt(Math.pow(x1 - x4, 2) + Math.pow(y1 - y4, 2));
