const lines = require('fs').readFileSync(0,'utf-8').trim().split('\n');
let idx = 0;
const T = parseInt(lines[idx++]);
for (let t = 0; t < T; t++) {
    const [x1, y1, x2, y2, x3, y3, x4, y4] = lines[idx++].trim().split(' ').map(Number);
    const area = 0.5 * ((x1 * y2 + x2 * y3 + x3 * y4 + x4 * y1) - (x2 * y1 + x3 * y2 + x4 * y3 + x1 * y4));
    const absArea = area < 0 ? -area : area;
    const perimeter = Math.sqrt(Math.pow(x2 - x1, 2) + Math.pow(y2 - y1, 2)) + Math.sqrt(Math.pow(x3 - x2, 2) + Math.pow(y3 - y2, 2)) + Math.sqrt(Math.pow(x4 - x3, 2) + Math.pow(y4 - y3, 2)) + Math.sqrt(Math.pow(x1 - x4, 2) + Math.pow(y1 - y4, 2));
    console.log(`Case ${t + 1}: ${Math.floor(absArea) + Math.floor(perimeter) + 1}`);
}

